import { test, expect } from '@playwright/test'
import path from 'path'
import { fileURLToPath } from 'url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const localUrl = `file://${path.resolve(__dirname, 'target-app/dashboard.html')}`

test('page loads with correct title and structure', async ({ page, browserName }) => {
    await page.goto(localUrl)
    
    // Check page title
    await expect(page).toHaveTitle('Dashboard — AutoHeal Demo')
});
